const fs = require('fs');
const path = require('path');

const REPO_ROOT = path.resolve(__dirname, '..');
const VERIFY_MODE = process.argv.includes('--verify');
const GENERATED_HEADER =
  '// AUTOGENERATED FROM src/utils/notificationRules/evaluation.ts — DO NOT EDIT. Run `npm run sync:functions-shared` from repo root.';

const SHARED_FILES = [
  {
    source: 'src/utils/notificationRules/evaluation.ts',
    destination: 'functions/src/utils/notificationRules/evaluation.ts',
    header: GENERATED_HEADER,
  },
];

function readFile(relativePath) {
  return fs.readFileSync(path.join(REPO_ROOT, relativePath), 'utf8');
}

function normalizeSource(content) {
  return content.endsWith('\n') ? content : `${content}\n`;
}

function generatedContent(file) {
  return `${file.header}\n\n${normalizeSource(readFile(file.source))}`;
}

function lineAt(lines, index) {
  return lines[index] === undefined ? '' : lines[index];
}

function buildDiff(expected, actual, destination) {
  const expectedLines = expected.split('\n');
  const actualLines = actual.split('\n');
  const maxLines = Math.max(expectedLines.length, actualLines.length);
  const diff = [`--- expected/${destination}`, `+++ actual/${destination}`];

  for (let index = 0; index < maxLines; index += 1) {
    if (lineAt(expectedLines, index) !== lineAt(actualLines, index)) {
      const start = Math.max(0, index - 2);
      const end = Math.min(maxLines, index + 3);

      diff.push(`@@ line ${index + 1} @@`);
      for (let lineIndex = start; lineIndex < end; lineIndex += 1) {
        const expectedLine = lineAt(expectedLines, lineIndex);
        const actualLine = lineAt(actualLines, lineIndex);

        if (expectedLine === actualLine) {
          diff.push(` ${expectedLine}`);
        } else {
          diff.push(`-${expectedLine}`);
          diff.push(`+${actualLine}`);
        }
      }

      break;
    }
  }

  return diff.join('\n');
}

function syncFile(file) {
  const destinationPath = path.join(REPO_ROOT, file.destination);
  const expected = generatedContent(file);
  const exists = fs.existsSync(destinationPath);
  const actual = exists ? readFile(file.destination) : '';
  const isSymlink = exists && fs.lstatSync(destinationPath).isSymbolicLink();

  if (actual === expected && !isSymlink) {
    return { status: 'current', file };
  }

  if (VERIFY_MODE) {
    return {
      status: 'stale',
      file,
      message: isSymlink
        ? `${file.destination} is a symlink; expected generated regular file.`
        : buildDiff(expected, actual, file.destination),
    };
  }

  fs.mkdirSync(path.dirname(destinationPath), { recursive: true });
  if (isSymlink) {
    fs.unlinkSync(destinationPath);
  }
  fs.writeFileSync(destinationPath, expected, 'utf8');

  return { status: 'synced', file };
}

const results = SHARED_FILES.map(syncFile);
const stale = results.filter((result) => result.status === 'stale');

if (stale.length > 0) {
  for (const result of stale) {
    console.error(`Shared functions copy is stale: ${result.file.destination}`);
    console.error(result.message);
  }
  process.exit(1);
}

for (const result of results) {
  if (result.status === 'synced') {
    console.log(`Synced ${result.file.source} -> ${result.file.destination}`);
  }
}
